mkdir -p /tmp/binlog-analyzer && cd /tmp/binlog-analyzer && cat > Program.cs << 'CSHARP'
using System;
using System.IO;
using System.IO.Compression;
using System.Text;
using System.Collections.Generic;

// Manual binlog parsing - read the raw records
// binlog is a gzip stream; let's decode and look for error strings
class Program
{
    static void Main(string[] args)
    {
        string binlogPath = args[0];

        // Read the gzip compressed binlog and search for meaningful strings
        using var fileStream = File.OpenRead(binlogPath);
        using var gzipStream = new GZipStream(fileStream, CompressionMode.Decompress);
        using var memStream = new MemoryStream();
        gzipStream.CopyTo(memStream);
        byte[] data = memStream.ToArray();

        Console.WriteLine($"Decompressed size: {data.Length} bytes");

        // Search for error-related strings in the binary data
        string text = Encoding.UTF8.GetString(data);

        // Find all lines containing "error" (case insensitive)
        var lines = new HashSet<string>();
        int idx = 0;
        while (idx < text.Length)
        {
            int errorIdx = text.IndexOf("error", idx, StringComparison.OrdinalIgnoreCase);
            if (errorIdx < 0) break;

            // Find line boundaries
            int lineStart = text.LastIndexOf('\n', Math.Max(0, errorIdx - 1));
            if (lineStart < 0) lineStart = 0; else lineStart++;
            int lineEnd = text.IndexOf('\n', errorIdx);
            if (lineEnd < 0) lineEnd = text.Length;

            // Extract a reasonable chunk around the error
            int contextStart = Math.Max(0, errorIdx - 200);
            int contextEnd = Math.Min(text.Length, errorIdx + 300);
            string context = text.Substring(contextStart, contextEnd - contextStart);

            // Clean non-printable chars
            var sb = new StringBuilder();
            foreach (char c in context)
            {
                if (c >= 32 || c == '\n' || c == '\r' || c == '\t')
                    sb.Append(c);
                else
                    sb.Append(' ');
            }
            string cleaned = sb.ToString().Trim();
            if (cleaned.Length > 10 && !lines.Contains(cleaned))
            {
                lines.Add(cleaned);
                Console.WriteLine("---");
                Console.WriteLine(cleaned);
            }

            idx = errorIdx + 5;
        }

        // Also search for .cs file references and .csproj references
        Console.WriteLine("\n=== Source File References ===");
        var csFiles = new HashSet<string>();
        idx = 0;
        while (idx < text.Length)
        {
            int csIdx = text.IndexOf(".cs", idx, StringComparison.Ordinal);
            if (csIdx < 0) break;

            // Extract filename
            int start = csIdx;
            while (start > 0 && text[start - 1] != ' ' && text[start - 1] != '\0' && text[start - 1] != '\n' && text[start - 1] < 128 && text[start - 1] >= 32)
                start--;
            string filename = text.Substring(start, csIdx + 3 - start);
            if (filename.EndsWith(".cs") && filename.Length > 3 && !filename.Contains("error"))
                csFiles.Add(filename);
            idx = csIdx + 3;
        }
        foreach (var f in csFiles)
            Console.WriteLine(f);
    }
}
