using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);

        Console.WriteLine($"Build Succeeded: {build.Succeeded}");
        Console.WriteLine($"Start: {build.StartTime}, End: {build.EndTime}");
        Console.WriteLine();

        // Collect all errors
        var errors = build.FindChildrenRecursive<Error>().ToList();
        Console.WriteLine($"=== ERRORS ({errors.Count} total) ===");
        foreach (var error in errors)
        {
            Console.WriteLine($"\nProject: {GetProjectName(error)}");
            Console.WriteLine($"  Code: {error.Code}");
            Console.WriteLine($"  File: {error.File}:{error.LineNumber},{error.ColumnNumber}");
            Console.WriteLine($"  Message: {error.Text}");
        }

        // Collect all warnings
        var warnings = build.FindChildrenRecursive<Warning>().ToList();
        Console.WriteLine($"\n=== WARNINGS ({warnings.Count} total) ===");
        foreach (var w in warnings)
        {
            Console.WriteLine($"\nProject: {GetProjectName(w)}");
            Console.WriteLine($"  Code: {w.Code}");
            Console.WriteLine($"  File: {w.File}:{w.LineNumber},{w.ColumnNumber}");
            Console.WriteLine($"  Message: {w.Text}");
        }

        // Show project evaluation results
        Console.WriteLine("\n=== PROJECT BUILD RESULTS ===");
        var projects = build.FindChildrenRecursive<Project>().ToList();
        foreach (var project in projects)
        {
            var projectErrors = project.FindChildrenRecursive<Error>().ToList();
            Console.WriteLine($"\nProject: {project.Name}");
            Console.WriteLine($"  Succeeded: {project.Succeeded}");
            Console.WriteLine($"  Errors: {projectErrors.Count}");
        }

        // Show source file contents embedded in the binlog if any
        Console.WriteLine("\n=== EMBEDDED FILES ===");
        var sourceFiles = build.SourceFiles;
        if (sourceFiles != null)
        {
            foreach (var kvp in sourceFiles)
            {
                Console.WriteLine($"\n--- {kvp.Key} ---");
                Console.WriteLine(kvp.Value);
            }
        }
        else
        {
            Console.WriteLine("No embedded source files found.");
        }
    }

    static string GetProjectName(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p.Name;
            current = current.Parent;
        }
        return "Unknown";
    }
}
