using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var build = BinaryLog.ReadBuild(args[0]);

        // Find the project.assets.json for Services
        var sourceFiles = build.SourceFiles;
        if (sourceFiles != null)
        {
            foreach (var sf in sourceFiles)
            {
                if (sf.FullPath.Contains("Services") && sf.FullPath.Contains("project.assets.json"))
                {
                    Console.WriteLine($"=== {sf.FullPath} ===");
                    // Just check if Newtonsoft is referenced
                    if (sf.Text.Contains("Newtonsoft"))
                        Console.WriteLine("  Newtonsoft.Json IS referenced in assets");
                    else
                        Console.WriteLine("  Newtonsoft.Json is NOT referenced in assets");

                    // Print package dependencies section
                    var lines = sf.Text.Split('\n');
                    foreach (var line in lines)
                    {
                        if (line.Contains("Newtonsoft") || line.Contains("newtonsoft"))
                            Console.WriteLine($"  {line.Trim()}");
                    }
                }
            }
        }

        // Print all messages related to package restore
        Console.WriteLine("\n=== RESTORE MESSAGES ===");
        var messages = build.FindChildrenRecursive<Message>().ToList();
        foreach (var m in messages)
        {
            if (m.Text != null && (m.Text.Contains("Newtonsoft") || m.Text.Contains("PackageReference")))
                Console.WriteLine(m.Text);
        }

        // Check if there were any Api.csproj errors (cascading)
        Console.WriteLine("\n=== Api.csproj BUILD STATUS ===");
        var tasks = build.FindChildrenRecursive<Task>().Where(t => t.Name == "Csc").ToList();
        foreach (var task in tasks)
        {
            string project = GetProjectName(task);
            bool hasErrors = task.FindChildrenRecursive<Error>().Any();
            Console.WriteLine($"  Csc in {project}: errors={hasErrors}");
        }

        // Check if Api even got to compile
        Console.WriteLine("\n=== ALL TARGETS WITH ERRORS ===");
        var targets = build.FindChildrenRecursive<Target>().Where(t => t.FindChildrenRecursive<Error>().Any()).ToList();
        foreach (var t in targets)
        {
            Console.WriteLine($"  Target: {t.Name} in {GetProjectName(t)}");
        }
    }

    static string GetProjectName(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p) return p.Name;
            current = current.Parent;
        }
        return "Unknown";
    }
}
